from datetime import datetime, timedelta, timezone
from typing import Optional

from fastapi import Depends, FastAPI, HTTPException, status
from fastapi.security import OAuth2PasswordBearer, OAuth2PasswordRequestForm
from jose import JWTError, jwt
from passlib.context import CryptContext
from pydantic import BaseModel

SECRET_KEY = 'change-me-in-production'
ALGORITHM = 'HS256'
ACCESS_TOKEN_EXPIRE_MINUTES = 30

app = FastAPI()

pwd_context = CryptContext(schemes=['bcrypt'], deprecated='auto')
oauth2_scheme = OAuth2PasswordBearer(tokenUrl='token')

fake_users_db: dict = {}
_next_id = 1


class UserIn(BaseModel):
    username: str
    password: str


class UserOut(BaseModel):
    id: int
    username: str


class Token(BaseModel):
    access_token: str
    token_type: str


def create_token(data: dict, expires_delta: Optional[timedelta] = None) -> str:
    to_encode = data.copy()
    expire = datetime.now(timezone.utc) + (expires_delta or timedelta(minutes=15))
    to_encode['exp'] = expire
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)


def get_current_user(token: str = Depends(oauth2_scheme)) -> dict:
    exc = HTTPException(
        status_code=status.HTTP_401_UNAUTHORIZED,
        detail='Could not validate credentials',
        headers={'WWW-Authenticate': 'Bearer'},
    )
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        username: str = payload.get('sub')
        if username is None:
            raise exc
    except JWTError:
        raise exc
    user = next((u for u in fake_users_db.values() if u['username'] == username), None)
    if user is None:
        raise exc
    return user


@app.post('/register', response_model=UserOut, status_code=201)
def register(body: UserIn):
    global _next_id
    if any(u['username'] == body.username for u in fake_users_db.values()):
        raise HTTPException(status_code=409, detail='Username already taken')
    uid = _next_id
    _next_id += 1
    fake_users_db[uid] = {
        'id': uid,
        'username': body.username,
        'hashed_password': pwd_context.hash(body.password),
    }
    return UserOut(id=uid, username=body.username)


@app.post('/token', response_model=Token)
def login(form_data: OAuth2PasswordRequestForm = Depends()):
    user = next((u for u in fake_users_db.values() if u['username'] == form_data.username), None)
    if not user or not pwd_context.verify(form_data.password, user['hashed_password']):
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail='Incorrect username or password',
            headers={'WWW-Authenticate': 'Bearer'},
        )
    token = create_token(
        data={'sub': user['username']},
        expires_delta=timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES),
    )
    return Token(access_token=token, token_type='bearer')


@app.get('/users/me', response_model=UserOut)
def read_users_me(current_user: dict = Depends(get_current_user)):
    return UserOut(id=current_user['id'], username=current_user['username'])

import time
from collections import defaultdict
from functools import wraps

from flask import Flask, jsonify, request

app = Flask(__name__)

_request_log: dict = defaultdict(list)
WINDOW_SECONDS = 60
MAX_REQUESTS = 10


def rate_limit(max_requests: int = MAX_REQUESTS, window: int = WINDOW_SECONDS):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            ip = request.remote_addr
            now = time.time()
            _request_log[ip] = [t for t in _request_log[ip] if now - t < window]
            if len(_request_log[ip]) >= max_requests:
                retry_after = window - int(now - _request_log[ip][0])
                return (
                    jsonify({'error': 'Rate limit exceeded', 'retry_after': retry_after}),
                    429,
                )
            _request_log[ip].append(now)
            return f(*args, **kwargs)
        return wrapped
    return decorator


@app.route('/api/data', methods=['GET'])
@rate_limit(max_requests=5, window=60)
def get_data():
    return jsonify({'data': 'some protected resource', 'ip': request.remote_addr}), 200


@app.route('/api/ping', methods=['GET'])
@rate_limit(max_requests=20, window=60)
def ping():
    return jsonify({'pong': True}), 200


@app.errorhandler(429)
def too_many_requests(e):
    return jsonify({'error': 'Too many requests'}), 429


