    app.run(debug=True)

import os
import uuid
from flask import Flask, jsonify, request, send_from_directory
from werkzeug.utils import secure_filename

UPLOAD_FOLDER = '/tmp/uploads'
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'pdf', 'txt'}
MAX_CONTENT_LENGTH = 5 * 1024 * 1024  # 5 MB

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
uploaded_files: dict = {}


def allowed_file(filename: str) -> bool:
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part in the request'}), 400
    f = request.files['file']
    if f.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    if not allowed_file(f.filename):
        return jsonify({'error': f'File type not allowed. Allowed: {sorted(ALLOWED_EXTENSIONS)}'}), 415
    safe_name = secure_filename(f.filename)
    unique_name = f'{uuid.uuid4().hex}_{safe_name}'
    dest = os.path.join(app.config['UPLOAD_FOLDER'], unique_name)
    f.save(dest)
    file_id = unique_name
    uploaded_files[file_id] = {
        'id': file_id,
        'original_name': safe_name,
        'stored_name': unique_name,
        'size': os.path.getsize(dest),
        'content_type': f.content_type,
    }
    return jsonify({'message': 'File uploaded', 'file': uploaded_files[file_id]}), 201


@app.route('/files', methods=['GET'])
def list_files():
    return jsonify({'files': list(uploaded_files.values())}), 200


@app.route('/files/<file_id>', methods=['GET'])
def download_file(file_id):
    meta = uploaded_files.get(file_id)
    if not meta:
        return jsonify({'error': 'File not found'}), 404
    return send_from_directory(
        app.config['UPLOAD_FOLDER'], meta['stored_name'], as_attachment=True
    )


@app.route('/files/<file_id>', methods=['DELETE'])
def delete_file(file_id):
    meta = uploaded_files.pop(file_id, None)
    if not meta:
        return jsonify({'error': 'File not found'}), 404
    path = os.path.join(app.config['UPLOAD_FOLDER'], meta['stored_name'])
    if os.path.exists(path):
        os.remove(path)
    return jsonify({'message': 'File deleted'}), 200


@app.errorhandler(413)
def request_entity_too_large(e):
    return jsonify({'error': 'File too large. Maximum size is 5 MB'}), 413


if __name__ == '__main__':
    app.run(debug=True)

import json
from typing import Dict, List

from fastapi import FastAPI, WebSocket, WebSocketDisconnect

app = FastAPI()


class ConnectionManager:
    def __init__(self):
        self.rooms: Dict[str, List[tuple]] = {}

    def _ensure_room(self, room_id: str):
        if room_id not in self.rooms:
            self.rooms[room_id] = []

    async def connect(self, room_id: str, websocket: WebSocket, username: str):
        await websocket.accept()
        self._ensure_room(room_id)
        self.rooms[room_id].append((websocket, username))
        await self.broadcast(
            room_id,
            {'type': 'system', 'message': f'{username} joined', 'room': room_id},
            exclude=websocket,
        )

    def disconnect(self, room_id: str, websocket: WebSocket) -> str:
        if room_id not in self.rooms:
            return 'unknown'
        username = next(
            (u for ws, u in self.rooms[room_id] if ws is websocket), 'unknown'
        )
        self.rooms[room_id] = [
            (ws, u) for ws, u in self.rooms[room_id] if ws is not websocket
        ]
        return username

    async def broadcast(
        self, room_id: str, message: dict, exclude: WebSocket = None
    ):
        if room_id not in self.rooms:
            return
        dead = []
        for ws, _username in self.rooms[room_id]:
            if ws is exclude:
                continue
            try:
                await ws.send_text(json.dumps(message))
            except Exception:
                dead.append(ws)
        self.rooms[room_id] = [
            (ws, u) for ws, u in self.rooms[room_id] if ws not in dead
        ]

    def room_members(self, room_id: str) -> List[str]:
        return [u for _ws, u in self.rooms.get(room_id, [])]


manager = ConnectionManager()


@app.websocket('/ws/{room_id}/{username}')
async def websocket_endpoint(websocket: WebSocket, room_id: str, username: str):
    await manager.connect(room_id, websocket, username)
    try:
        while True:
            text = await websocket.receive_text()
            await manager.broadcast(
                room_id,
                {'type': 'message', 'from': username, 'message': text, 'room': room_id},
            )
    except WebSocketDisconnect:
        left = manager.disconnect(room_id, websocket)
        await manager.broadcast(
            room_id,
            {'type': 'system', 'message': f'{left} left', 'room': room_id},
        )


@app.get('/rooms/{room_id}/members')
def room_members(room_id: str):
    return {'room': room_id, 'members': manager.room_members(room_id)}


@app.get('/rooms')
def list_rooms():
    return {
        'rooms': [
            {'id': rid, 'member_count': len(members)}
            for rid, members in manager.rooms.items()
        ]
    }

