from typing import Generator, List, Optional

from fastapi import Depends, FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()


# ── Fake database layer ───────────────────────────────────────────────────────

class FakeDB:
    def __init__(self):
        self._store: dict = {}
        self._next_id: int = 1

    def get(self, model: str, pk: int) -> Optional[dict]:
        return self._store.get((model, pk))

    def all(self, model: str) -> List[dict]:
        return [v for (m, _), v in self._store.items() if m == model]

    def insert(self, model: str, data: dict) -> dict:
        pk = self._next_id
        self._next_id += 1
        record = {'id': pk, **data}
        self._store[(model, pk)] = record
        return record

    def update(self, model: str, pk: int, data: dict) -> Optional[dict]:
        rec = self._store.get((model, pk))
        if rec is None:
            return None
        rec.update(data)
        return rec

    def delete(self, model: str, pk: int) -> bool:
        return self._store.pop((model, pk), None) is not None

    def commit(self):
        pass  # no-op in this in-memory implementation

    def rollback(self):
        pass


_db_instance = FakeDB()


def get_db() -> Generator[FakeDB, None, None]:
    db = _db_instance
    try:
        yield db
        db.commit()
    except Exception:
        db.rollback()
        raise


