import os
import uuid

from flask import Flask, jsonify, request

app = Flask(__name__)
UPLOAD_FOLDER = '/tmp/products'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

products: dict = {}
_next_id = 1


@app.route('/products', methods=['POST'])
def create_product():
    global _next_id
    name = request.form.get('name', '').strip()
    price_raw = request.form.get('price', '')
    description = request.form.get('description', '')

    errors = {}
    if not name:
        errors['name'] = 'required'
    try:
        price = float(price_raw)
        if price < 0:
            errors['price'] = 'must be non-negative'
    except (ValueError, TypeError):
        errors['price'] = 'must be a number'
    if errors:
        return jsonify({'errors': errors}), 422

    image_url = None
    if 'image' in request.files:
        img = request.files['image']
        if img.filename:
            ext = img.filename.rsplit('.', 1)[-1].lower()
            if ext not in {'jpg', 'jpeg', 'png', 'webp'}:
                return jsonify({'error': 'Image must be jpg/jpeg/png/webp'}), 415
            fname = f'{uuid.uuid4().hex}.{ext}'
            img.save(os.path.join(UPLOAD_FOLDER, fname))
            image_url = f'/static/products/{fname}'

    pid = _next_id
    _next_id += 1
    products[pid] = {
        'id': pid,
        'name': name,
        'price': price,
        'description': description,
        'image_url': image_url,
    }
    return jsonify(products[pid]), 201


@app.route('/products', methods=['GET'])
def list_products():
    return jsonify({'products': list(products.values())}), 200


@app.route('/products/<int:pid>', methods=['GET'])
def get_product(pid):
    p = products.get(pid)
    if not p:
        return jsonify({'error': 'Product not found'}), 404
    return jsonify(p), 200


if __name__ == '__main__':
    app.run(debug=True)

from datetime import datetime, timezone
from typing import List, Optional

from fastapi import APIRouter, FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI(title='Blog API')


# ── Models ────────────────────────────────────────────────────────────────────

class PostCreate(BaseModel):
    title: str
    body: str
    author_id: int


class Post(BaseModel):
    id: int
    title: str
    body: str
    author_id: int
    comment_count: int = 0
    created_at: str


class CommentCreate(BaseModel):
    author_name: str
    text: str


class Comment(BaseModel):
    id: int
    post_id: int
    author_name: str
    text: str
    created_at: str


# ── In-memory stores ──────────────────────────────────────────────────────────

posts: dict = {}
comments: dict = {}   # post_id -> list[dict]
_post_id = 1
_comment_id = 1


# ── Posts router ─────────────────────────────────────────────────────────────

posts_router = APIRouter(prefix='/posts', tags=['posts'])


@posts_router.get('', response_model=List[Post])
def list_posts(author_id: Optional[int] = None):
    result = list(posts.values())
    if author_id is not None:
        result = [p for p in result if p['author_id'] == author_id]
    return result


@posts_router.post('', response_model=Post, status_code=201)
def create_post(body: PostCreate):
    global _post_id
    post = {
        **body.model_dump(),
        'id': _post_id,
        'comment_count': 0,
        'created_at': datetime.now(timezone.utc).isoformat(),
    }
    posts[_post_id] = post
    comments[_post_id] = []
    _post_id += 1
    return post


@posts_router.get('/{post_id}', response_model=Post)
def get_post(post_id: int):
    p = posts.get(post_id)
    if not p:
        raise HTTPException(status_code=404, detail=f'Post {post_id} not found')
    return p


@posts_router.delete('/{post_id}', status_code=204)
def delete_post(post_id: int):
    if not posts.pop(post_id, None):
        raise HTTPException(status_code=404, detail=f'Post {post_id} not found')
    comments.pop(post_id, None)


# ── Comments router ───────────────────────────────────────────────────────────

comments_router = APIRouter(prefix='/posts/{post_id}/comments', tags=['comments'])


@comments_router.get('', response_model=List[Comment])
def list_comments(post_id: int):
    if post_id not in posts:
        raise HTTPException(status_code=404, detail=f'Post {post_id} not found')
    return comments.get(post_id, [])


@comments_router.post('', response_model=Comment, status_code=201)
def add_comment(post_id: int, body: CommentCreate):
    global _comment_id
    if post_id not in posts:
        raise HTTPException(status_code=404, detail=f'Post {post_id} not found')
    c = {
        **body.model_dump(),
        'id': _comment_id,
        'post_id': post_id,
        'created_at': datetime.now(timezone.utc).isoformat(),
    }
    comments[post_id].append(c)
    posts[post_id]['comment_count'] += 1
    _comment_id += 1
    return c


app.include_router(posts_router)
app.include_router(comments_router)

import time
import threading
from functools import wraps

from flask import Flask, jsonify, request

app = Flask(__name__)

_lock = threading.Lock()


class TokenBucket:
    """Thread-safe token bucket rate limiter."""

    def __init__(self, capacity: int, refill_rate: float):
        self.capacity = capacity
        self.refill_rate = refill_rate  # tokens per second
        self._buckets: dict = {}

    def _refill(self, key: str) -> float:
        now = time.monotonic()
        if key not in self._buckets:
            self._buckets[key] = (float(self.capacity), now)
            return float(self.capacity)
        tokens, last = self._buckets[key]
        elapsed = now - last
        tokens = min(float(self.capacity), tokens + elapsed * self.refill_rate)
        self._buckets[key] = (tokens, now)
        return tokens

    def consume(self, key: str, tokens: int = 1) -> bool:
        with _lock:
            available = self._refill(key)
            if available >= tokens:
                cur_tokens, ts = self._buckets[key]
                self._buckets[key] = (cur_tokens - tokens, ts)
                return True
            return False


def rate_limit(bucket: TokenBucket, tokens: int = 1, key_func=None):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            key = key_func(request) if key_func else request.remote_addr
            if not bucket.consume(key, tokens):
                return jsonify({'error': 'Rate limit exceeded'}), 429
            return f(*args, **kwargs)
        return wrapped
    return decorator


standard_bucket = TokenBucket(capacity=10, refill_rate=1.0)
premium_bucket  = TokenBucket(capacity=50, refill_rate=5.0)


@app.route('/api/free', methods=['GET'])
@rate_limit(standard_bucket, tokens=1)
def free_endpoint():
    return jsonify({'tier': 'free', 'data': 'standard response'}), 200


@app.route('/api/premium', methods=['GET'])
@rate_limit(premium_bucket, tokens=1)
def premium_endpoint():
    return jsonify({'tier': 'premium', 'data': 'fast response'}), 200


@app.route('/api/expensive', methods=['POST'])
@rate_limit(standard_bucket, tokens=3)
def expensive_operation():
    return jsonify({'result': 'heavy computation done'}), 200


if __name__ == '__main__':
    app.run(debug=True)

import asyncio
import json
from typing import AsyncGenerator

from fastapi import FastAPI, HTTPException, Query
from fastapi.responses import StreamingResponse

app = FastAPI()

_records = [{'id': i, 'value': i * i, 'label': f'item_{i}'} for i in range(1, 501)]


async def _stream_json_array(
    records: list, chunk_size: int
) -> AsyncGenerator[str, None]:
    yield '['
    total = len(records)
    for idx, record in enumerate(records):
        await asyncio.sleep(0)
        sep = ',' if idx < total - 1 else ''
        yield json.dumps(record) + sep
        if (idx + 1) % chunk_size == 0:
            await asyncio.sleep(0.05)
    yield ']'


async def _stream_ndjson(records: list) -> AsyncGenerator[str, None]:
    for record in records:
        await asyncio.sleep(0)
        yield json.dumps(record) + '\n'


@app.get('/stream/json-array')
def stream_as_array(
    min_id: int = Query(1, ge=1),
    max_id: int = Query(100, ge=1),
    chunk_size: int = Query(20, ge=1, le=100),
):
    filtered = [r for r in _records if min_id <= r['id'] <= max_id]
    return StreamingResponse(
        _stream_json_array(filtered, chunk_size),
        media_type='application/json',
        headers={'X-Total-Count': str(len(filtered))},
    )


@app.get('/stream/ndjson')
def stream_as_ndjson(
    min_id: int = Query(1, ge=1),
    max_id: int = Query(100, ge=1),
):
    filtered = [r for r in _records if min_id <= r['id'] <= max_id]
    if not filtered:
        raise HTTPException(status_code=404, detail='No records found in range')
    return StreamingResponse(
        _stream_ndjson(filtered),
        media_type='application/x-ndjson',
        headers={'X-Total-Count': str(len(filtered))},
    )


@app.get('/stream/sse')
async def server_sent_events(count: int = Query(5, ge=1, le=50)):
    async def generate():
        for i in range(1, count + 1):
            await asyncio.sleep(0.5)
            data = json.dumps({'event': i, 'total': count})
            yield f'data: {data}\n\n'
        yield 'data: {"event": "done"}\n\n'

    return StreamingResponse(generate(), media_type='text/event-stream')

from functools import wraps

from flask import Flask, jsonify, request
from flask_jwt_extended import (
    JWTManager, create_access_token, get_jwt,
    jwt_required,
)
from werkzeug.security import check_password_hash, generate_password_hash

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'rbac-secret-key'
jwt = JWTManager(app)

users = {
    1: {
        'id': 1, 'username': 'alice',
        'password_hash': generate_password_hash('alice123'),
        'roles': ['admin', 'editor'],
    },
    2: {
        'id': 2, 'username': 'bob',
        'password_hash': generate_password_hash('bob123'),
        'roles': ['editor'],
    },
    3: {
        'id': 3, 'username': 'carol',
        'password_hash': generate_password_hash('carol123'),
        'roles': ['viewer'],
    },
}


def roles_required(*required_roles):
    """Decorator that demands at least one of the required_roles in the JWT."""
    def decorator(f):
        @wraps(f)
        @jwt_required()
        def wrapped(*args, **kwargs):
            claims = get_jwt()
            user_roles = set(claims.get('roles', []))
            if not user_roles.intersection(required_roles):
                return (
                    jsonify({'error': 'Insufficient permissions',
                             'required': list(required_roles)}),
                    403,
                )
            return f(*args, **kwargs)
        return wrapped
    return decorator


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json() or {}
    username = data.get('username', '')
    password = data.get('password', '')
    user = next((u for u in users.values() if u['username'] == username), None)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    token = create_access_token(
        identity=username,
        additional_claims={'roles': user['roles']},
    )
    return jsonify({'token': token, 'roles': user['roles']}), 200


@app.route('/admin/dashboard', methods=['GET'])
@roles_required('admin')
def admin_dashboard():
    return jsonify({'message': 'Welcome, admin', 'user_count': len(users)}), 200


@app.route('/content', methods=['POST'])
@roles_required('admin', 'editor')
def create_content():
    data = request.get_json() or {}
    return jsonify({'message': 'Content created', 'title': data.get('title', 'untitled')}), 201


@app.route('/content', methods=['GET'])
@roles_required('admin', 'editor', 'viewer')
def read_content():
    return jsonify({'articles': ['Article A', 'Article B']}), 200


if __name__ == '__main__':
    app.run(debug=True)

import hashlib
import secrets
from datetime import datetime, timezone
from typing import Optional

from fastapi import Depends, FastAPI, Header, HTTPException, status
from pydantic import BaseModel

app = FastAPI()

_api_keys: dict = {}  # hashed_key -> metadata dict


def _hash_key(raw: str) -> str:
    return hashlib.sha256(raw.encode()).hexdigest()


class ApiKeyMeta(BaseModel):
    name: str
    created_at: str
    last_used: Optional[str] = None
    requests: int = 0


class KeyCreateRequest(BaseModel):
    name: str


class KeyCreateResponse(BaseModel):
    key: str
    name: str
    message: str


async def get_api_key(
    x_api_key: str = Header(..., alias='X-API-Key')
) -> ApiKeyMeta:
    hashed = _hash_key(x_api_key)
    meta = _api_keys.get(hashed)
    if not meta:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail='Invalid or missing API key',
            headers={'WWW-Authenticate': 'ApiKey'},
        )
    meta['last_used'] = datetime.now(timezone.utc).isoformat()
    meta['requests'] += 1
    return ApiKeyMeta(**meta)


@app.post('/api-keys', response_model=KeyCreateResponse, status_code=201)
def create_api_key(body: KeyCreateRequest):
    raw_key = secrets.token_urlsafe(32)
    hashed = _hash_key(raw_key)
    _api_keys[hashed] = {
        'name': body.name,
        'created_at': datetime.now(timezone.utc).isoformat(),
        'last_used': None,
        'requests': 0,
    }
    return KeyCreateResponse(
        key=raw_key,
        name=body.name,
        message='Store this key safely — it will not be shown again.',
    )


@app.get('/protected/data')
def protected_data(key_meta: ApiKeyMeta = Depends(get_api_key)):
    return {'data': 'secret value', 'accessed_by': key_meta.name}


@app.get('/protected/stats')
def my_stats(key_meta: ApiKeyMeta = Depends(get_api_key)):
    return {
        'name': key_meta.name,
        'requests': key_meta.requests,
        'last_used': key_meta.last_used,
    }

import hashlib
import hmac
from functools import wraps

from flask import Flask, jsonify, request

app = Flask(__name__)

WEBHOOK_SECRET = 'my-webhook-secret'


def verify_signature(payload: bytes, secret: str, signature_header: str) -> bool:
    if not signature_header or not signature_header.startswith('sha256='):
        return False
    expected = 'sha256=' + hmac.new(
        secret.encode(), payload, hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected, signature_header)


def require_webhook_signature(secret: str):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            sig_header = request.headers.get('X-Hub-Signature-256', '')
            raw_body = request.get_data()  # must read before get_json()
            if not verify_signature(raw_body, secret, sig_header):
                return jsonify({'error': 'Invalid webhook signature'}), 401
            return f(*args, **kwargs)
        return wrapped
    return decorator


@app.route('/webhook/github', methods=['POST'])
@require_webhook_signature(WEBHOOK_SECRET)
def github_webhook():
    event = request.headers.get('X-GitHub-Event', 'unknown')
    body = request.get_json(force=True) or {}
    return jsonify({
        'received': event,
        'action': body.get('action'),
        'repository': body.get('repository', {}).get('name'),
    }), 200


@app.route('/webhook/test', methods=['POST'])
def test_webhook():
    body = request.get_json(force=True) or {}
    return jsonify({'echo': body}), 200


if __name__ == '__main__':
    app.run(debug=True)
